INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'location', 'permanent campus under construction, temporary at NH-39 Mantripukhri Heingang Manipur 795002, surrounded by Police HQ/High Court/CRPF, calm location with mountains, Swiggy/Zomato till 9pm deliver to boys hostel', 'IIIT Manipur permanent campus is under construction. The temporary campus is located at NH-39, Mantripukhri, Heingang, Manipur 795002. It is surrounded by Police HQ, High Court, and CRPF, making it a calm and secure location with mountain views. Swiggy and Zomato deliver to the boys hostel until 9 PM.', 1, '02/04/26 11:28 am', '02/04/26 11:28 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'transport', 'Imphal Airport 12km, Dimapur railway 190km, Guwahati railway 450km', 'IIIT Manipur is 12 km from Imphal Airport, 190 km from Dimapur Railway Station, and 450 km from Guwahati Railway Station.', 1, '02/04/26 11:28 am', '02/04/26 11:28 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'restaurants', 'KK South Indian Cafe, D4 Cafe near campus, Dominos/KFC/Le Zara/Blue Moon/Pizza Hut after 3km, Swiggy/Zomato available', 'Nearby restaurants around IIIT Manipur: KK South Indian Cafe and D4 Cafe are near campus. Dominos, KFC, Le Zara, Blue Moon, and Pizza Hut are available after 3 km. Swiggy and Zomato delivery services are also available.', 1, '02/04/26 11:28 am', '02/04/26 11:28 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'tourist', 'Marjing Polo Statue 5.3km, Kangla Fort 4km, Langol Hills behind campus, Loktak Lake 50km, waterfalls mostly closed security concerns', 'Tourist spots near IIIT Manipur: Marjing Polo Statue (5.3 km), Kangla Fort (4 km), Langol Hills (behind campus), and Loktak Lake (50 km). Waterfalls are mostly closed due to security concerns.', 1, '02/04/26 11:28 am', '02/04/26 11:28 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'malls', 'Mamcy Mall 3km (KFC), Kumecs City Centre 10km (Vishal Mart), Bazaar India Rudraksha Mall, Airport Shopping Mall 10km', 'Shopping areas near IIIT Manipur: Mamcy Mall (3 km, has KFC), Kumecs City Centre (10 km, has Vishal Mart), Bazaar India Rudraksha Mall, and Airport Shopping Mall (10 km).', 1, '02/04/26 11:28 am', '02/04/26 11:28 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'climate', 'avg 25C morning 15C night, winter 18C morning 5-6C night heavy fog, summer 25-30C morning 20-22C night, heavy monsoon rains', 'IIIT Manipur climate: Average temperature is 25C in the morning and 15C at night. Winter temperature is 18C in the morning and 5-6C at night with heavy fog. Summer temperature is 25-30C in the morning and 20-22C at night. Heavy monsoon rains occur during the rainy season.', 1, '02/04/26 11:28 am', '02/04/26 11:28 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'language', 'campus English+Hindi, locals also understand English+Hindi', 'At IIIT Manipur, the campus language is English and Hindi. Locals in the area also understand English and Hindi.', 1, '02/04/26 11:28 am', '02/04/26 11:28 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'clubs', 'Technical Clubs (8): VIDYUT (VLSI/Embedded), SYNAPSE (AI/ML), Coding Club (DSA), Cyber Security, Android Dev, Cloud Computing, Mathematica, Web Dev. Cultural (6): YouTube X Film Making, Photography, Sketchers Studio, Octavia Music, Stand-up IIITM, Fashion Fusion. Additional (5): Qurbat, Darshanam (Literature/Debate), Readers Club', 'IIIT Manipur has 8 technical clubs: VIDYUT (VLSI/Embedded Systems), SYNAPSE (AI/ML), Coding Club (DSA), Cyber Security Club, Android Development Club, Cloud Computing Club, Mathematica Club, and Web Development Club. There are 6 cultural clubs: YouTube X Film Making, Photography Club, Sketchers Studio, Octavia Music Club, Stand-up IIITM, and Fashion Fusion. Additionally there are 5 more clubs: Qurbat, Darshanam (Literature and Debate), and Readers Club.', 1, '02/04/26 11:42 am', '02/04/26 11:42 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'attendance', 'Attendance 75% mandatory per subject', 'At IIIT Manipur, 75% attendance is mandatory per subject.', 1, '02/04/26 11:44 am', '02/04/26 11:44 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'wifi', 'WiFi - Jio 5G in every hostel decent speed', 'IIIT Manipur does not have institute WiFi. However, Jio 5G is available in every hostel with decent speed.', 1, '02/04/26 11:45 am', '02/04/26 11:45 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'fests', 'Ahouba annual 3 days, singers/bands invited, coding/hackathons/project showcases, music/dance/stand-up/fashion, cash prizes, food stalls', 'IIIT Manipur hosts Ahouba, an annual 3-day fest. It features invited singers and bands, coding competitions, hackathons, project showcases, music, dance, stand-up comedy, fashion shows, cash prizes, and food stalls.', 1, '02/04/26 11:50 am', '02/04/26 11:50 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'hostels', 'Boys Hostels - 7 HB 1-7 inside campus min 12 rooms max 4 per room. KMR Hostel 2km 6 floors 14 rooms/floor max 2 per room bus provided. Mantripukhri Hostel 300m 5 floors sharing based on room. Girls Hostels - 2 within campus, 3 floors, 6 rooms/floor, sharing based on room', 'IIIT Manipur boys hostels: 7 hostels (HB-1 to HB-7) inside campus with minimum 12 rooms each, maximum 4 students per room. KMR Hostel is 2 km away with 6 floors, 14 rooms per floor, maximum 2 per room, bus service provided. Mantripukhri Hostel is 300 m from campus with 5 floors, sharing based on room size. Girls hostels: 2 hostels within campus, 3 floors each, 6 rooms per floor, sharing based on room size.', 2, '02/04/26 11:55 am', '02/04/26 12:32 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'elections', 'Elections once per 2 semesters, some positions reserved by year/gender', 'At IIIT Manipur, student council elections are held once every 2 semesters. Some positions are reserved by year and gender.', 1, '02/04/26 11:58 am', '02/04/26 11:58 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'sports', 'Football, E-Sports, Badminton, Chess, Kabaddi, Table Tennis, Athletics, Volleyball, Cricket, Basketball. Facilities: common cricket/football ground, 2 badminton courts, 1 basketball court, 2 TT setups, 2 volleyball courts', 'Sports at IIIT Manipur: Football, E-Sports, Badminton, Chess, Kabaddi, Table Tennis, Athletics, Volleyball, Cricket, and Basketball. Facilities include a common cricket/football ground, 2 badminton courts, 1 basketball court, 2 table tennis setups, and 2 volleyball courts.', 1, '02/04/26 12:02 pm', '02/04/26 12:02 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'shops', 'A3 mart 200m for groceries, fruit/veg market 200m', 'Near IIIT Manipur, A3 Mart is 200 m away for groceries, and a fruit/vegetable market is also 200 m away.', 1, '02/04/26 12:04 pm', '02/04/26 12:04 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'fines', 'not fined unless Director level, ID card loss Rs 10000, serious indiscipline Rs 10000', 'At IIIT Manipur, fines are not imposed unless it reaches the Director level. ID card loss incurs a fine of Rs 10,000. Serious indiscipline also carries a fine of Rs 10,000.', 1, '02/04/26 12:07 pm', '02/04/26 12:07 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'gym', 'no gym inside campus, gym in front of campus Rs 1000/month', 'IIIT Manipur does not have a gym inside campus. There is a gym in front of the campus available at Rs 1,000 per month.', 1, '02/04/26 12:08 pm', '02/04/26 12:08 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'medical', 'no clinic, basic first aid only, medical insurance provided', 'IIIT Manipur does not have a clinic on campus. Only basic first aid is available. Medical insurance is provided to all students.', 1, '02/04/26 12:10 pm', '02/04/26 12:10 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'mess', 'Mess timings: Breakfast regular 7-9AM holidays 7:30-9:30AM, Lunch 12-2PM, Snacks 4:30-5:30PM, Dinner 7-9PM', 'IIIT Manipur mess timings: Breakfast 7:00-9:00 AM (holidays 7:30-9:30 AM), Lunch 12:00-2:00 PM, Snacks 4:30-5:30 PM, Dinner 7:00-9:00 PM.', 1, '02/04/26 12:12 pm', '02/04/26 12:12 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Manipur', 'ambassador_message', 'fee_structure', 'Tuition Rs 1,40,000/sem all semesters. Exam Fee Rs 2,400/sem. Gymkhana Rs 2,000/sem. Admission Fee Rs 5,000 1st sem only. Caution Money Rs 10,000 1st sem refundable. Medical Insurance Rs 2,500/year odd semesters. Alumni Rs 6,000 4th sem. Convocation Rs 6,000 8th sem. Hostel Rent Rs 8,000/sem. Fan/Elec/Water Rs 2,000/sem. Hostel Fund Rs 2,000/sem. Mess Advance Rs 45,000/sem (9000x5). Mess Deposit Rs 5,000 1st sem refundable. Hall Mess Establishment Rs 1,000 1st sem. Grand Total Sem 1 Rs 2,24,900. NO concession for any category.', 'IIIT Manipur fee structure: Tuition fee is Rs 1,40,000 per semester for all 8 semesters. Other semester charges include Exam Fee Rs 2,400, Gymkhana Rs 2,000. First semester has additional one-time charges: Admission Fee Rs 5,000, Caution Money Rs 10,000 (refundable), and Hall Mess Establishment Rs 1,000. Medical Insurance Rs 2,500 per year charged in odd semesters. Alumni fee Rs 6,000 in 4th semester, Convocation fee Rs 6,000 in 8th semester. Hostel charges per semester: Rent Rs 8,000, Fan/Electricity/Water Rs 2,000, Hostel Fund Rs 2,000. Mess charges: Advance Rs 45,000 per semester (Rs 9,000 x 5 months), Deposit Rs 5,000 (1st semester, refundable). Grand total for 1st semester is Rs 2,24,900. There is NO fee concession for any category.', 1, '02/04/26 11:28 am', '02/04/26 11:28 am', 'pdf_ocr');
